/**
 * Generate Italian B1-B2 flashcard deck (nodes 11-20).
 * IDs start at 4001. Output: src/data/italian/b1b2.json
 */
const fs = require('fs');
const path = require('path');

const OUT = path.join(__dirname, '..', 'src', 'data', 'italian', 'b1b2.json');
fs.mkdirSync(path.dirname(OUT), { recursive: true });

let nextId = 4001;
const cards = [];

const T_KW = {
  travel: ['viaggio','valigia','aereo','treno','hotel','città','museo','ristorante','vacanz','turista','bigliett','stazione','aeroporto','prenot','spiaggia','montagna','paese','visita','mappa','guida','volo','partire','arriv','destinazione','escursion','crociera','albergo','campeggio','passaporto','itinerario','nave','autobus','metro','taxi','porto','isola','sosta','autostrada','parcheggio','alloggio'],
  work: ['lavoro','ufficio','riunione','collega','capo','azienda','progetto','cliente','stipendio','contratto','colloquio','direttore','presentazione','scadenza','report','email','professionale','carriera','impresa','manager','promozione','fattura','team','dipartimento','budget','impiegat','assumer','licenziare','curriculum','congresso','stage','tirocinio'],
  family: ['madre','padre','mamma','papà','fratello','sorella','figlio','figlia','nonno','nonna','zio','zia','cugino','famiglia','marito','moglie','bambino','bambina','genitor','nipot','casa','cucinare','giardino','amore','cane','gatto','festa','compleanno','sposare','matrimonio','vicino','amico','amica','sentire','felice','triste','preoccup','abbraccia']
};

function assignTags(it, en) {
  const text = (it + ' ' + en).toLowerCase();
  const tags = ['general'];
  for (const [tag, kws] of Object.entries(T_KW)) {
    if (kws.some(k => text.includes(k))) tags.push(tag);
  }
  if (tags.length < 2) {
    const pool = ['travel', 'work', 'family'];
    tags.push(pool[nextId % 3]);
  }
  return tags;
}

function add(node, rows) {
  for (const r of rows) {
    const c = {
      id: nextId,
      target: r[0],
      english: r[1],
      audio: `it-${nextId}.mp3`,
      tags: assignTags(r[0], r[1]),
      grammarNode: 'node-' + String(node).padStart(2, '0')
    };
    if (r[2]) c.grammar = r[2];
    nextId++;
    cards.push(c);
  }
}

